package com.google.gson.internal.bind;
import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.JsonObject;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.MalformedJsonException;
import java.io.IOException;
import java.io.Reader;
import java.util.Arrays;
import java.util.Iterator;
import java.util.Map;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader jsonTreeReader;

  private void callExpect(JsonTreeReader reader, JsonToken token) throws Exception {
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);
    expectMethod.invoke(reader, token);
  }

  private void mockExpectToDoNothing(JsonTreeReader spyReader) throws Exception {
    // Using Mockito doAnswer to mock private method expect via reflection
    // Since expect is private, we cannot mock it directly with Mockito.
    // Instead, we create a spy and override expect via reflection with a no-op.
    // But Mockito can't mock private methods directly.
    // So we replace expect with a no-op by creating a subclass override via proxy or reflection.
    // Here, we will use reflection to set a flag or patch the method via a dynamic proxy is complicated.
    // Instead, we will use a workaround: override nextBoolean to skip expect call in tests
    // but since we want to test nextBoolean, we can't do that.
    // So the simplest way is to suppress expect by reflection:
    // We create a new JsonTreeReader subclass that overrides expect to do nothing.
    // But since we must keep the test as is, we will call expect via reflection in tests where needed.
    // So in the test, we will NOT mock expect but suppress its effect by calling expect via reflection before nextBoolean call.
    // So no mocking expect here.
  }

  @BeforeEach
  public void setUp() throws Exception {
    // Create a dummy JsonPrimitive Boolean true to push to stack
    JsonPrimitive truePrimitive = new JsonPrimitive(true);

    // Create JsonTreeReader instance with dummy JsonPrimitive (using constructor)
    jsonTreeReader = new JsonTreeReader(truePrimitive);

    // Use reflection to set stack and stackSize properly for testing nextBoolean
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = new Object[32];
    stack[0] = truePrimitive;
    stackField.set(jsonTreeReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndicesField.set(jsonTreeReader, pathIndices);

    // Spy on jsonTreeReader to verify calls, but do NOT mock private expect method (private cannot be mocked)
    jsonTreeReader = spy(jsonTreeReader);
  }

  @Test
  public void testNextBoolean_ReturnsBooleanAndIncrementsPathIndices() throws Exception {
    // Initially pathIndices[0] = 0
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    assertEquals(0, pathIndices[0]);

    // Call nextBoolean
    // Since expect is private and cannot be mocked, call nextBoolean directly.
    boolean result = jsonTreeReader.nextBoolean();

    // Instead of verifying expect call (private method), verify behaviour:
    // Result should be true (as per JsonPrimitive pushed)
    assertTrue(result);

    // pathIndices[0] should be incremented by 1
    assertEquals(1, pathIndices[0]);
  }

  @Test
  public void testNextBoolean_WithStackSizeZero_DoesNotIncrementPathIndices() throws Exception {
    // Set stackSize to 0 before call
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 0);

    // Setup stack with JsonPrimitive true at index 0
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = new Object[32];
    stack[0] = new JsonPrimitive(true);
    stackField.set(jsonTreeReader, stack);

    // Call nextBoolean, should return true and not increment pathIndices (since stackSize == 0)
    boolean result = jsonTreeReader.nextBoolean();

    // pathIndices should remain unchanged (all zeros)
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(jsonTreeReader);
    for (int i = 0; i < pathIndices.length; i++) {
      assertEquals(0, pathIndices[i]);
    }

    assertTrue(result);
  }

  @Test
  public void testNextBoolean_ThrowsIfStackTopNotJsonPrimitive() throws Exception {
    // Push a non-JsonPrimitive object on stack to cause ClassCastException
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stack = new Object[32];
    stack[0] = new Object(); // Not JsonPrimitive
    stackField.set(jsonTreeReader, stack);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(jsonTreeReader, 1);

    // Expect ClassCastException when nextBoolean tries to cast Object to JsonPrimitive
    assertThrows(ClassCastException.class, () -> jsonTreeReader.nextBoolean());
  }
}
